return [{
  fajr: $json.data.timings.Fajr,
  dhuhr: $json.data.timings.Dhuhr,
  asr: $json.data.timings.Asr,
  maghrib: $json.data.timings.Maghrib,
  isha: $json.data.timings.Isha,
}];

const prayer = $items("reformat prayer")[0].json;

const events = [];

events.push({title: "Shalat Subuh", time: prayer.fajr});
events.push({title: "Shalat Dzuhur", time: prayer.dhuhr});
events.push({title: "Shalat Ashar", time: prayer.asr});
events.push({title: "Shalat Maghrib", time: prayer.maghrib});
events.push({title: "Shalat Isya", time: prayer.isha});

// Doa
events.push({title: "Doa Pagi", time: prayer.fajr});
events.push({title: "Doa Petang", time: prayer.asr});

// Ayamul Bidh
if ($json.isAyamulBidh) {
  events.push({title: "Puasa Sunnah Ayamul Bidh", time: "04:30"});
}

const today = $now.setZone("Asia/Jakarta").toFormat("yyyy-MM-dd");

return events.map(e => {
  const cleanTime = e.time.split(" ")[0];

  // 🔥 tambah durasi 10 menit
  const endTime = $moment(`${today} ${cleanTime}`)
    .add(10, 'minutes')
    .format('HH:mm:ss');

  return {
    json: {
      title: `${e.title} - ${today}`,
      start: `${today}T${cleanTime}:00`,
      end: `${today}T${endTime}`
    }
  };
});
